class Solution {
    public double minTime(int n, int k, int m, int[] time, double[] mul) {
        double[][] dp = new double[n + 1][m];
        for (int i = 1; i <= n; i++) {
            for (int j = 0; j < m; j++) {
                dp[i][j] = Double.POSITIVE_INFINITY;
            }
        }
        dp[0][0] = 0;
        for (int i = 1; i <= n; i++) {
            for (int j = 0; j < m; j++) {
                for (int p = 1; p <= Math.min(i, k); p++) {
                    double timeToCross = Math.max(time[i - p], dp[i - p][j]) * mul[j];
                    int nextStage = (int) ((timeToCross / m) + j) % m;
                    dp[i][j] = Math.min(dp[i][j], timeToCross + (p == i ? 0 : mul[nextStage] * time[i - p]));
                }
            }
        }
        return dp[n][0] == Double.POSITIVE_INFINITY ? -1 : dp[n][0];
    }
}
